export const conceptRssXml = "<?xml version=\"1.0\" encoding=\"UTF-8\"?><rss version=\"2.0\"><channel><title>Kurs.ing Kommune</title><description>Kommunesider for deg som skal søke, drive eller endre servering, salg eller arrangement med alkohol i Norge.</description><link>https://www.kurs.ing/kommune/</link><language>nb-no</language><item><title>Arendal: skjenketider, bevilling og lokale regler</title><link>https://www.kurs.ing/arendal/</link><guid isPermaLink=\"true\">https://www.kurs.ing/arendal/</guid><description>Arendal er en av kommunene der sesong faktisk betyr noe for driften. I juli, august og desember kan serveringssteder holde åpent til 02.30, mens resten av året stopper ordinær åpningstid kl. 02.00. Samler søknad, innsyn og lokale regler i én side med lenker tilbake til originalkildene.</description><pubDate>Sun, 12 Apr 2026 00:00:00 GMT</pubDate></item><item><title>Nord-Aurdal: skjenketider, bevilling og lokale regler</title><link>https://www.kurs.ing/nord-aurdal/</link><guid isPermaLink=\"true\">https://www.kurs.ing/nord-aurdal/</guid><description>Nord-Aurdal kombinerer relativt romslige skjenketider inne med en klar grense ute: øl og vin kan skjenkes fra 08.00 til 02.00, brennevin fra 13.00 til 02.00, men uteservering stopper ved midnatt. Samler søknad, innsyn og lokale regler i én side med lenker tilbake til originalkildene.</description><pubDate>Sun, 12 Apr 2026 00:00:00 GMT</pubDate></item><item><title>Bjerkreim: skjenketider, bevilling og lokale regler</title><link>https://www.kurs.ing/bjerkreim/</link><guid isPermaLink=\"true\">https://www.kurs.ing/bjerkreim/</guid><description>Bjerkreim er strengere enn mange kommuner på sprit: øl og vin kan skjenkes til 01.00, mens brennevin stopper allerede kl. 00.00. Viser også forskjellen mellom øl og vin og brennevin der kommunen oppgir ulike grenser.</description><pubDate>Sun, 12 Apr 2026 00:00:00 GMT</pubDate></item><item><title>Bremanger: skjenketider, bevilling og lokale regler</title><link>https://www.kurs.ing/bremanger/</link><guid isPermaLink=\"true\">https://www.kurs.ing/bremanger/</guid><description>Bremanger har et tydelig og relativt lesbart oppsett: øl og vin fra 08.00 til 02.00, brennevin fra 13.00 til 02.00 og konsumstopp 30 minutter etter skjenkeslutt. Samler søknad, innsyn og lokale regler i én side med lenker tilbake til originalkildene.</description><pubDate>Sun, 12 Apr 2026 00:00:00 GMT</pubDate></item></channel></rss>";
